"""
zhanla — SDK for defining AI components as classes.

Public API:
    zhanla.Tool(name, description, input_schema, fn, output_schema)
    zhanla.CodeEval(name, description, fn)
    zhanla.Skill(name, description, instructions, ...)
    zhanla.Runner(client=...)
    zhanla.Agent(name, description, instructions, model, runner, ...)
    zhanla.LLMProcessor(name, description, instructions, model, runner, ...)
    zhanla.LLMEval(name, description, instructions, model, runner, ...)
    zhanla.Orchestration(name, description, steps)
    zhanla.Step(component, name, next)
    zhanla.Conditional(condition, if_true, if_false)
    zhanla.Checklist(name, description, evals, weights)
    zhanla.EvalTree(name, description, root)
    zhanla.Branch(eval, threshold, if_pass, if_fail)
    zhanla.Edge(weight, node)
    zhanla.Leaf(eval)

    zhanla.wrap(client)  — observe an LLM client (Anthropic / OpenAI / Gemini)
"""

